const rows = Array.isArray($json.rows) ? $json.rows : [];
const sourceSystem = typeof $json.sourceSystem === 'string' ? $json.sourceSystem : 'partner_file';
const workflowName = 'adl-file-intake';
const runKey = `${sourceSystem}-${Date.now()}`;
const leads = rows.map((row, index) => ({
  sourceRecordId: String(row.sourceRecordId ?? row.external_id ?? `${sourceSystem}-${index}`),
  sourceUrl: row.sourceUrl ?? null,
  category: String(row.category ?? row.vertical ?? ''),
  location: {
    latitude: Number(row.latitude ?? row.lat),
    longitude: Number(row.longitude ?? row.lon),
  },
  normalizedDetails: row.normalizedDetails ?? {
    name: row.name ?? null,
    brand: row.brand ?? null,
  },
  rawPayload: row,
  evidenceUrls: Array.isArray(row.evidenceUrls) ? row.evidenceUrls : [],
  freshnessAt: row.freshnessAt ?? new Date().toISOString(),
  priority: row.priority ?? 'medium',
}));
return [{ json: { runKey, workflowName, sourceSystem, triggerType: 'file', startedAt: new Date().toISOString(), completedAt: new Date().toISOString(), leads } }];
